What does this code do?

const UserList = React.memo(function UserList({ users }: { users: User[] }) {
  return (
    <ul>
      {users.map(u => <li key={u.id}>{u.name}</li>)}
    </ul>
  );
});

What is the output of this render cycle?

function Parent() {
  const [count, setCount] = useState(0);
  const memoizedList = useMemo(() => [1, 2, 3], []);

  return (
    <div>
      <MemoizedChild list={memoizedList} />
      <button onClick={() => setCount(c => c + 1)}>{count}</button>
    </div>
  );
}

const MemoizedChild = React.memo(function Child({ list }: { list: number[] }) {
  console.log('Child rendered');
  return <div>{list.join(',')}</div>;
});

What is the output of this component tree during React 18 concurrent rendering?

function App() {
  return (
    <React.Suspense fallback={<Spinner />}>
      <Dashboard />
    </React.Suspense>
  );
}

// Dashboard suspends if user is not loaded
function Dashboard() {
  const user = useSuspenseQuery({ queryKey: ['user'], queryFn: fetchUser });
  return <div>{user.name}</div>;
}
